7	// Recursively discovers all registry namespaces including nested ones.
8	export async function resolveRegistryNamespaces(
9	  components: string[],
10	  config: Config
11	) {
12	  const discoveredNamespaces = new Set<string>()
13	  const visitedItems = new Set<string>()
14	  const itemsToProcess = [...components]
15	
16	  while (itemsToProcess.length > 0) {
17	    const currentItem = itemsToProcess.shift()!
18	
19	    if (visitedItems.has(currentItem)) {
20	      continue
21	    }
22	    visitedItems.add(currentItem)
23	
24	    const { registry } = parseRegistryAndItemFromString(currentItem)
25	    if (registry && !BUILTIN_REGISTRIES[registry]) {
26	      discoveredNamespaces.add(registry)
27	    }
28	
29	    try {
30	      const [item] = await fetchRegistryItems([currentItem], config, {
31	        useCache: true,
32	      })
33	
34	      if (item?.registryDependencies) {
35	        for (const dep of item.registryDependencies) {
36	          const { registry: depRegistry } = parseRegistryAndItemFromString(dep)
37	          if (depRegistry && !BUILTIN_REGISTRIES[depRegistry]) {
38	            discoveredNamespaces.add(depRegistry)
39	          }
40	
41	          if (!visitedItems.has(dep)) {
42	            itemsToProcess.push(dep)
43	          }
44	        }
45	      }
46	    } catch (error) {
47	      // If a registry is not configured, we still track it.
48	      if (error instanceof RegistryNotConfiguredError) {
49	        const { registry } = parseRegistryAndItemFromString(currentItem)
50	        if (registry && !BUILTIN_REGISTRIES[registry]) {
51	          discoveredNamespaces.add(registry)
52	        }
53	        continue
54	      }
55	
56	      // For other errors (network, parsing, etc.), we skip this item
57	      // but continue processing others to discover as many namespaces as possible.
58	      continue
59	    }
60	  }
61	
62	  return Array.from(discoveredNamespaces)
63	}
64	

