## Implementation Plan: Stepper Compound Component for shadcn/ui

### Overview

The Stepper is a pure-React compound component (no Radix-UI dependency) that follows the same Context + custom-hook pattern as `carousel.tsx`. It uses two nested contexts, controlled/uncontrolled state management, `data-slot` / `data-state` / `data-orientation` attributes throughout, and the standard `cn()` + `React.ComponentProps` conventions.

---

### File 1: `apps/v4/registry/new-york-v4/ui/stepper.tsx`

**Full file content:**

```tsx
"use client"

import * as React from "react"

import { cn } from "@/lib/utils"

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

type StepperOrientation = "horizontal" | "vertical"
type StepState = "active" | "completed" | "inactive"

type StepperContextProps = {
  activeStep: number
  setActiveStep: (step: number) => void
  orientation: StepperOrientation
}

type StepperItemContextProps = {
  step: number
  state: StepState
}

// ---------------------------------------------------------------------------
// Contexts
// ---------------------------------------------------------------------------

const StepperContext = React.createContext<StepperContextProps | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }
  return context
}

const StepperItemContext = React.createContext<StepperItemContextProps | null>(
  null
)

function useStepperItem() {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error("useStepperItem must be used within a <StepperItem />")
  }
  return context
}

// ---------------------------------------------------------------------------
// Stepper (root)
// ---------------------------------------------------------------------------

type StepperProps = {
  activeStep?: number
  defaultStep?: number
  onStepChange?: (step: number) => void
  orientation?: StepperOrientation
}

function Stepper({
  activeStep: activeStepProp,
  defaultStep = 0,
  onStepChange,
  orientation = "horizontal",
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & StepperProps) {
  const [internalStep, setInternalStep] = React.useState(defaultStep)

  const isControlled = activeStepProp !== undefined
  const activeStep = isControlled ? activeStepProp : internalStep

  const setActiveStep = React.useCallback(
    (step: number) => {
      if (!isControlled) {
        setInternalStep(step)
      }
      onStepChange?.(step)
    },
    [isControlled, onStepChange]
  )

  return (
    <StepperContext.Provider value={{ activeStep, setActiveStep, orientation }}>
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "flex",
          orientation === "horizontal"
            ? "flex-row items-start"
            : "flex-col",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

// ---------------------------------------------------------------------------
// StepperItem
// ---------------------------------------------------------------------------

type StepperItemProps = {
  step: number
}

function StepperItem({
  step,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & StepperItemProps) {
  const { activeStep, orientation } = useStepper()

  const state: StepState =
    step === activeStep
      ? "active"
      : step < activeStep
        ? "completed"
        : "inactive"

  return (
    <StepperItemContext.Provider value={{ step, state }}>
      <div
        data-slot="stepper-item"
        data-state={state}
        data-orientation={orientation}
        className={cn(
          "flex",
          orientation === "horizontal"
            ? "flex-col items-center"
            : "flex-row gap-4",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

// ---------------------------------------------------------------------------
// StepperTrigger
// ---------------------------------------------------------------------------

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { setActiveStep } = useStepper()
  const { step, state } = useStepperItem()

  return (
    <button
      type="button"
      data-slot="stepper-trigger"
      data-state={state}
      onClick={() => setActiveStep(step)}
      className={cn(
        "inline-flex items-center gap-2 rounded-md text-sm font-medium transition-colors outline-none",
        "focus-visible:border-ring focus-visible:ring-[3px] focus-visible:ring-ring/50",
        "disabled:pointer-events-none disabled:opacity-50",
        className
      )}
      {...props}
    >
      {children}
    </button>
  )
}

// ---------------------------------------------------------------------------
// StepperTitle
// ---------------------------------------------------------------------------

function StepperTitle({
  className,
  ...props
}: React.ComponentProps<"p">) {
  const { state } = useStepperItem()

  return (
    <p
      data-slot="stepper-title"
      data-state={state}
      className={cn("text-sm font-medium", className)}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperDescription
// ---------------------------------------------------------------------------

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  const { state } = useStepperItem()

  return (
    <p
      data-slot="stepper-description"
      data-state={state}
      className={cn("text-xs text-muted-foreground", className)}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperSeparator
// ---------------------------------------------------------------------------

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = useStepper()

  return (
    <div
      data-slot="stepper-separator"
      data-orientation={orientation}
      className={cn(
        "bg-muted-foreground/30",
        orientation === "horizontal"
          ? "h-px flex-1 mt-4"
          : "w-px min-h-6 ms-4",
        className
      )}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperContent
// ---------------------------------------------------------------------------

type StepperContentProps = {
  step?: number
}

function StepperContent({
  step: stepProp,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & StepperContentProps) {
  const { activeStep } = useStepper()

  // When used outside StepperItem, stepProp is required.
  // When used inside StepperItem, fall back to item context.
  const itemContext = React.useContext(StepperItemContext)
  const resolvedStep = stepProp !== undefined ? stepProp : itemContext?.step

  if (resolvedStep === undefined) {
    throw new Error(
      "StepperContent requires either a `step` prop or a <StepperItem /> ancestor"
    )
  }

  const isActive = resolvedStep === activeStep

  if (!isActive) return null

  return (
    <div
      data-slot="stepper-content"
      data-state="active"
      className={cn("mt-4", className)}
      {...props}
    >
      {children}
    </div>
  )
}

// ---------------------------------------------------------------------------
// Exports
// ---------------------------------------------------------------------------

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
}
```

**Key design decisions:**

- `StepperContent` uses `React.useContext(StepperItemContext)` directly (not the throwing hook) so it works both inside and outside `StepperItem`. When used outside, it requires the `step` prop; when inside, it inherits from item context.
- `StepperSeparator` reads `orientation` from the root `StepperContext` (not item context), so it can be placed between `StepperItem` elements at the root level.
- The controlled/uncontrolled pattern mirrors React's own patterns: `defaultStep` seeds internal state; once `activeStep` prop is supplied, the component defers entirely to it and routes clicks through `onStepChange`.
- `StepperTrigger` is a native `<button>` (not Radix Slot) because no `asChild` prop is needed, keeping the component zero-dependency.

---

### File 2: `apps/v4/registry/new-york-v4/examples/stepper-demo.tsx`

**Full file content:**

```tsx
"use client"

import * as React from "react"

import { Button } from "@/registry/new-york-v4/ui/button"
import {
  Stepper,
  StepperContent,
  StepperDescription,
  StepperItem,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/registry/new-york-v4/ui/stepper"

const STEPS = [
  {
    step: 0,
    title: "Account",
    description: "Create your account",
  },
  {
    step: 1,
    title: "Profile",
    description: "Set up your profile",
  },
  {
    step: 2,
    title: "Review",
    description: "Confirm your details",
  },
]

export default function StepperDemo() {
  const [activeStep, setActiveStep] = React.useState(0)

  const isFirst = activeStep === 0
  const isLast = activeStep === STEPS.length - 1

  return (
    <div className="flex w-full max-w-2xl flex-col gap-8">
      <Stepper activeStep={activeStep} onStepChange={setActiveStep}>
        {STEPS.map((s, index) => (
          <React.Fragment key={s.step}>
            <StepperItem step={s.step} className="flex-1">
              <StepperTrigger className="flex-col items-center gap-1.5 px-2">
                <span
                  className={[
                    "flex size-8 items-center justify-center rounded-full border-2 text-xs font-semibold transition-colors",
                    s.step === activeStep
                      ? "border-primary bg-primary text-primary-foreground"
                      : s.step < activeStep
                        ? "border-primary bg-primary/10 text-primary"
                        : "border-muted-foreground/40 bg-background text-muted-foreground",
                  ].join(" ")}
                >
                  {s.step + 1}
                </span>
                <div className="flex flex-col items-center gap-0.5">
                  <StepperTitle>{s.title}</StepperTitle>
                  <StepperDescription>{s.description}</StepperDescription>
                </div>
              </StepperTrigger>
            </StepperItem>
            {index < STEPS.length - 1 && <StepperSeparator />}
          </React.Fragment>
        ))}
      </Stepper>

      {STEPS.map((s) => (
        <StepperContent key={s.step} step={s.step}>
          {s.step === 0 && (
            <div className="rounded-lg border p-6">
              <h3 className="mb-2 font-semibold">Account Details</h3>
              <p className="text-sm text-muted-foreground">
                Fill in your email and choose a password to create your account.
              </p>
            </div>
          )}
          {s.step === 1 && (
            <div className="rounded-lg border p-6">
              <h3 className="mb-2 font-semibold">Profile Setup</h3>
              <p className="text-sm text-muted-foreground">
                Add your name, avatar, and a short bio so others can find you.
              </p>
            </div>
          )}
          {s.step === 2 && (
            <div className="rounded-lg border p-6">
              <h3 className="mb-2 font-semibold">Review &amp; Submit</h3>
              <p className="text-sm text-muted-foreground">
                Everything looks good! Click &ldquo;Finish&rdquo; to complete
                your registration.
              </p>
            </div>
          )}
        </StepperContent>
      ))}

      <div className="flex justify-between">
        <Button
          variant="outline"
          onClick={() => setActiveStep((s) => Math.max(0, s - 1))}
          disabled={isFirst}
        >
          Back
        </Button>
        <Button
          onClick={() =>
            isLast
              ? setActiveStep(0)
              : setActiveStep((s) => Math.min(STEPS.length - 1, s + 1))
          }
        >
          {isLast ? "Finish" : "Next"}
        </Button>
      </div>
    </div>
  )
}
```

**Demo design notes:**

- Controlled: parent owns `activeStep` with `useState(0)` and passes both `activeStep` and `onStepChange` to `<Stepper>`.
- `StepperContent` is placed outside the `Stepper` block (using the `step` prop), demonstrating the outside-item usage pattern.
- The numbered circle indicator is rendered inline in `StepperTrigger` as a `<span>` — this keeps the demo self-contained without needing extra icon imports.
- `React.Fragment` with `key` is used so `StepperSeparator` can be interspersed without introducing a wrapping element.
- "Finish" resets to step 0, which makes the demo easily re-runnable.

---

### File 3: Registry entry for `ui/_registry.ts`

The `"stepper"` entry slots alphabetically between `"sonner"` (line 543) and `"spinner"` (line 554 after insertion), not between `"sonner"` and `"switch"` — note that `"spinner"` already exists in the file between those two. The correct alphabetical position is after `"sonner"` and before `"spinner"`.

Looking at the actual registry content:
- Line 542: `"sonner"` ends at line 552
- Line 553: `"spinner"` begins at line 553
- Line 564: `"switch"` begins at line 564

Alphabetically: `"sonner"` < `"spinner"` < `"stepper"` is incorrect — `"stepper"` sorts after `"spinner"` (ste > spi). The correct order is: `"sonner"` < `"spinner"` < `"stepper"` < `"switch"`.

So the entry inserts **after** `"spinner"` (line 563) and **before** `"switch"` (line 564).

**Entry to append after the closing brace of the `"spinner"` block (after line 563):**

```typescript
  {
    name: "stepper",
    type: "registry:ui",
    files: [
      {
        path: "ui/stepper.tsx",
        type: "registry:ui",
      },
    ],
  },
```

No `dependencies` array is needed (zero npm dependencies — pure React + Tailwind). No `registryDependencies` needed either since `cn` comes from `@/lib/utils` which is not a registry item.

---

