// ---------------------------------------------------------------------------
// StepperContent
// ---------------------------------------------------------------------------

function StepperContent({
  step: stepProp,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & { step?: number }) {
  const { activeStep } = useStepper()
  // Use React.useContext directly (not the throwing hook) so this works
  // both inside <StepperItem> (no step prop needed) and outside it (step prop required).
  const itemContext = React.useContext(StepperItemContext)
  const resolvedStep = stepProp !== undefined ? stepProp : itemContext?.step

  if (resolvedStep === undefined) {
    throw new Error(
      "StepperContent requires either a `step` prop or a <StepperItem /> ancestor"
    )
  }

  if (resolvedStep !== activeStep) return null

  return (
    <div
