# Plan: Add Stepper Compound Component to shadcn/ui

## Context

The project needs a `Stepper` compound component for multi-step wizards and onboarding flows. No stepper component currently exists in the codebase. This is a pure-React implementation (no Radix UI primitive exists for steppers) following the same **Context + custom hook** pattern as `carousel.tsx`. The component must support horizontal and vertical orientations, expose 7 sub-components, and include a demo example — all registered in the appropriate `_registry.ts` files.

**Constraint:** Do NOT modify any existing component files. Only create new files and add registry entries.

---

## Critical Files

| Action | File |
|--------|------|
| **CREATE** | `apps/v4/registry/new-york-v4/ui/stepper.tsx` |
| **CREATE** | `apps/v4/registry/new-york-v4/examples/stepper-demo.tsx` |
| **MODIFY** (append entry) | `apps/v4/registry/new-york-v4/ui/_registry.ts` |
| **MODIFY** (append entry) | `apps/v4/registry/new-york-v4/examples/_registry.ts` |
| No change needed | `apps/v4/registry/new-york-v4/registry.ts` (auto-imports sub-registries) |

### Reference patterns (read only)
- `apps/v4/registry/new-york-v4/ui/carousel.tsx` — Context + custom hook pattern
- `apps/v4/registry/new-york-v4/ui/tabs.tsx` — `data-orientation` pattern
- `apps/v4/registry/new-york-v4/examples/tabs-demo.tsx` — demo file format

---

## Step 1 — Create `ui/stepper.tsx`

Create `/apps/v4/registry/new-york-v4/ui/stepper.tsx` with the following complete content:

```tsx
"use client"

import * as React from "react"

import { cn } from "@/lib/utils"

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

type StepperOrientation = "horizontal" | "vertical"
type StepState = "active" | "completed" | "inactive"

// ---------------------------------------------------------------------------
// Root Context
// ---------------------------------------------------------------------------

type StepperContextProps = {
  activeStep: number
  setActiveStep: (step: number) => void
  orientation: StepperOrientation
}

const StepperContext = React.createContext<StepperContextProps | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }
  return context
}

// ---------------------------------------------------------------------------
// Item Context
// ---------------------------------------------------------------------------

type StepperItemContextProps = {
  step: number
  state: StepState
}

const StepperItemContext =
  React.createContext<StepperItemContextProps | null>(null)

function useStepperItem() {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error("useStepperItem must be used within a <StepperItem />")
  }
  return context
}

// ---------------------------------------------------------------------------
// Stepper (root)
// ---------------------------------------------------------------------------

function Stepper({
  activeStep: activeStepProp,
  defaultStep = 0,
  onStepChange,
  orientation = "horizontal",
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  activeStep?: number
  defaultStep?: number
  onStepChange?: (step: number) => void
  orientation?: StepperOrientation
}) {
  const [internalStep, setInternalStep] = React.useState(defaultStep)

  const isControlled = activeStepProp !== undefined
  const activeStep = isControlled ? activeStepProp : internalStep

  const setActiveStep = React.useCallback(
    (step: number) => {
      if (!isControlled) {
        setInternalStep(step)
      }
      onStepChange?.(step)
    },
    [isControlled, onStepChange]
  )

  return (
    <StepperContext.Provider value={{ activeStep, setActiveStep, orientation }}>
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "flex",
          orientation === "horizontal" ? "flex-row items-start" : "flex-col",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

// ---------------------------------------------------------------------------
// StepperItem
// ---------------------------------------------------------------------------

function StepperItem({
  step,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & { step: number }) {
  const { activeStep, orientation } = useStepper()

  const state: StepState =
    step === activeStep ? "active" : step < activeStep ? "completed" : "inactive"

  return (
    <StepperItemContext.Provider value={{ step, state }}>
      <div
        data-slot="stepper-item"
        data-state={state}
        data-orientation={orientation}
        className={cn(
          "flex",
          orientation === "horizontal"
            ? "flex-col items-center"
            : "flex-row gap-4",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

// ---------------------------------------------------------------------------
// StepperTrigger
// ---------------------------------------------------------------------------

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { setActiveStep } = useStepper()
  const { step, state } = useStepperItem()

  return (
    <button
      type="button"
      data-slot="stepper-trigger"
      data-state={state}
      onClick={() => setActiveStep(step)}
      className={cn(
        "inline-flex items-center gap-2 rounded-md text-sm font-medium transition-colors outline-none",
        "focus-visible:border-ring focus-visible:ring-[3px] focus-visible:ring-ring/50",
        "disabled:pointer-events-none disabled:opacity-50",
        className
      )}
      {...props}
    >
      {children}
    </button>
  )
}

// ---------------------------------------------------------------------------
// StepperTitle
// ---------------------------------------------------------------------------

function StepperTitle({ className, ...props }: React.ComponentProps<"p">) {
  const { state } = useStepperItem()

  return (
    <p
      data-slot="stepper-title"
      data-state={state}
      className={cn("text-sm font-medium", className)}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperDescription
// ---------------------------------------------------------------------------

function StepperDescription({ className, ...props }: React.ComponentProps<"p">) {
  const { state } = useStepperItem()

  return (
    <p
      data-slot="stepper-description"
      data-state={state}
      className={cn("text-xs text-muted-foreground", className)}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperSeparator
// ---------------------------------------------------------------------------

function StepperSeparator({ className, ...props }: React.ComponentProps<"div">) {
  const { orientation } = useStepper()

  return (
    <div
      data-slot="stepper-separator"
      data-orientation={orientation}
      aria-hidden
      className={cn(
        "bg-muted-foreground/30",
        orientation === "horizontal" ? "h-px flex-1 mt-4" : "w-px min-h-6 ms-4",
        className
      )}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperContent
// ---------------------------------------------------------------------------

function StepperContent({
  step: stepProp,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & { step?: number }) {
  const { activeStep } = useStepper()
  // Use React.useContext directly (not the throwing hook) so this works
  // both inside <StepperItem> (no step prop needed) and outside it (step prop required).
  const itemContext = React.useContext(StepperItemContext)
  const resolvedStep = stepProp !== undefined ? stepProp : itemContext?.step

  if (resolvedStep === undefined) {
    throw new Error(
      "StepperContent requires either a `step` prop or a <StepperItem /> ancestor"
    )
  }

  if (resolvedStep !== activeStep) return null

  return (
    <div
      data-slot="stepper-content"
      data-state="active"
      className={cn("mt-4", className)}
      {...props}
    >
      {children}
    </div>
  )
}

// ---------------------------------------------------------------------------
// Exports
// ---------------------------------------------------------------------------

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
  useStepper,
}
```

### Key design decisions
- **`"use client"`** is required — the component uses `useState`, `useCallback`, `useContext`.
- **Two contexts**: `StepperContext` (root-level: orientation + active step) and `StepperItemContext` (per-item: step index + computed state).
- **`StepperSeparator`** reads from `StepperContext` (not item context) — separators live between items at root level.
- **`StepperContent`** uses bare `React.useContext(StepperItemContext)` — not the throwing hook — so it can work both inside and outside `<StepperItem>`.
- **Controlled/uncontrolled**: `isControlled = activeStepProp !== undefined` (strict undefined check so step `0` is a valid controlled value).
- **Separator alignment**: `mt-4` in horizontal mode aligns the `h-px` line with the center of a `size-8` (2rem) step indicator circle. `ms-4` in vertical mode aligns the `w-px` line under the circle center.
- **No external dependencies** — pure React + `cn()`. No `dependencies` field needed in registry entry.

---

## Step 2 — Create `examples/stepper-demo.tsx`

Create `/apps/v4/registry/new-york-v4/examples/stepper-demo.tsx`:

