  )
}

// ---------------------------------------------------------------------------
// Exports
// ---------------------------------------------------------------------------

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
  useStepper,
}
```

### Key design decisions
- **`"use client"`** is required — the component uses `useState`, `useCallback`, `useContext`.
- **Two contexts**: `StepperContext` (root-level: orientation + active step) and `StepperItemContext` (per-item: step index + computed state).
- **`StepperSeparator`** reads from `StepperContext` (not item context) — separators live between items at root level.
- **`StepperContent`** uses bare `React.useContext(StepperItemContext)` — not the throwing hook — so it can work both inside and outside `<StepperItem>`.
- **Controlled/uncontrolled**: `isControlled = activeStepProp !== undefined` (strict undefined check so step `0` is a valid controlled value).
- **Separator alignment**: `mt-4` in horizontal mode aligns the `h-px` line with the center of a `size-8` (2rem) step indicator circle. `ms-4` in vertical mode aligns the `w-px` line under the circle center.
- **No external dependencies** — pure React + `cn()`. No `dependencies` field needed in registry entry.

---

## Step 2 — Create `examples/stepper-demo.tsx`

Create `/apps/v4/registry/new-york-v4/examples/stepper-demo.tsx`:

```tsx
"use client"

import * as React from "react"

import { Button } from "@/registry/new-york-v4/ui/button"
import {
  Stepper,
  StepperContent,
  StepperDescription,
  StepperItem,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/registry/new-york-v4/ui/stepper"

const STEPS = [
  { step: 0, title: "Account", description: "Create your account" },
  { step: 1, title: "Profile", description: "Set up your profile" },
  { step: 2, title: "Review", description: "Confirm your details" },
]

export default function StepperDemo() {
  const [activeStep, setActiveStep] = React.useState(0)

  const isFirst = activeStep === 0
  const isLast = activeStep === STEPS.length - 1

  return (
    <div className="flex w-full max-w-2xl flex-col gap-8">
      <Stepper activeStep={activeStep} onStepChange={setActiveStep}>
        {STEPS.map((s, index) => (
          <React.Fragment key={s.step}>
            <StepperItem step={s.step} className="flex-1">
              <StepperTrigger className="flex-col items-center gap-1.5 px-2">
                <span
                  className={[
                    "flex size-8 items-center justify-center rounded-full border-2 text-xs font-semibold transition-colors",
                    s.step === activeStep
                      ? "border-primary bg-primary text-primary-foreground"
                      : s.step < activeStep
                        ? "border-primary bg-primary/10 text-primary"
                        : "border-muted-foreground/40 bg-background text-muted-foreground",
                  ].join(" ")}
                >
                  {s.step + 1}
                </span>
                <div className="flex flex-col items-center gap-0.5">
                  <StepperTitle>{s.title}</StepperTitle>
                  <StepperDescription>{s.description}</StepperDescription>
                </div>
              </StepperTrigger>
            </StepperItem>
            {index < STEPS.length - 1 && <StepperSeparator />}
          </React.Fragment>
        ))}
      </Stepper>

      {STEPS.map((s) => (
        <StepperContent key={s.step} step={s.step}>
          {s.step === 0 && (
            <div className="rounded-lg border p-6">
              <h3 className="mb-2 font-semibold">Account Details</h3>
              <p className="text-sm text-muted-foreground">
                Fill in your email and choose a password to create your account.
              </p>
            </div>
          )}
          {s.step === 1 && (
            <div className="rounded-lg border p-6">
              <h3 className="mb-2 font-semibold">Profile Setup</h3>
              <p className="text-sm text-muted-foreground">
                Add your name, avatar, and a short bio so others can find you.
              </p>
            </div>
          )}
          {s.step === 2 && (
            <div className="rounded-lg border p-6">
              <h3 className="mb-2 font-semibold">Review &amp; Submit</h3>
              <p className="text-sm text-muted-foreground">
                Everything looks good! Click &ldquo;Finish&rdquo; to complete
                your registration.
              </p>
            </div>
          )}
        </StepperContent>
      ))}

      <div className="flex justify-between">
        <Button
          variant="outline"
          onClick={() => setActiveStep((s) => Math.max(0, s - 1))}
          disabled={isFirst}
        >
          Back
        </Button>
        <Button
          onClick={() =>
            isLast
              ? setActiveStep(0)
              : setActiveStep((s) => Math.min(STEPS.length - 1, s + 1))
          }
        >
          {isLast ? "Finish" : "Next"}
        </Button>
      </div>
    </div>
  )
}
```

### Demo design decisions
- **Controlled mode**: parent owns `activeStep` with `useState(0)`, passes both `activeStep` and `onStepChange` down.
- **`StepperContent` used outside `<StepperItem>`** (below the `<Stepper>` block) using the `step` prop — demonstrates the flexible placement pattern.
- **Numbered circle indicator**: rendered inline as a `<span>` in `StepperTrigger` — no icon import needed, self-contained.
- **`React.Fragment` with `key`**: allows `StepperSeparator` to be interspersed without a wrapping element.
- **"Finish" resets to step 0**: makes the demo re-runnable in the docs sandbox.
- Imports: `@/registry/new-york-v4/ui/button` and `@/registry/new-york-v4/ui/stepper`.

